INSERT INTO products (sku, name, description, brand_id, category_id, mrp, price, gst_rate, image_urls, is_active, is_featured, search_keywords, tags, specifications, popularity, view_count) VALUES
('RB-AVI-002', 'Ray-Ban Aviator Classic Gold', 'Iconic aviator frame with gold metal finish. Double bridge design for superior comfort and style.', '4028d001-d3ed-46a1-a744-96e3d6f5a0e4', '1d33ac1e-c860-4122-9c40-2ebe5c63203b', 12999, 8999, 18, ARRAY['https://images.pexels.com/photos/39716/pexels-photo-39716.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/1362558/pexels-photo-1362558.jpeg?auto=compress&cs=tinysrgb&w=600'], true, true, ARRAY['ray-ban','aviator','gold','metal','men','classic','premium'], ARRAY['frames','men','metal','aviator','classic'], '{"frame_shape": "Aviator", "material": "Metal", "color": "Gold", "gender": "Men", "size": "Medium", "weight": "25g", "warranty": "1 Year"}', 200, 1500),
('RB-WAY-002', 'Ray-Ban Wayfarer Classic Black', 'Legendary wayfarer frame in black acetate. Timeless design that never goes out of style.', '4028d001-d3ed-46a1-a744-96e3d6f5a0e4', '1d33ac1e-c860-4122-9c40-2ebe5c63203b', 9999, 6999, 18, ARRAY['https://images.pexels.com/photos/701841/pexels-photo-701841.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/947885/pexels-photo-947885.jpeg?auto=compress&cs=tinysrgb&w=600'], true, true, ARRAY['ray-ban','wayfarer','black','acetate','unisex','classic'], ARRAY['frames','unisex','acetate','wayfarer','classic'], '{"frame_shape": "Wayfarer", "material": "Acetate", "color": "Black", "gender": "Unisex", "size": "Medium", "weight": "32g", "warranty": "1 Year"}', 180, 1200),
('RB-ROU-002', 'Ray-Ban Round Metal Vintage', 'Vintage round metal frame with thin temples. Intellectual and artistic look.', '4028d001-d3ed-46a1-a744-96e3d6f5a0e4', '1d33ac1e-c860-4122-9c40-2ebe5c63203b', 8999, 5999, 18, ARRAY['https://images.pexels.com/photos/147641/pexels-photo-147641.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/1362558/pexels-photo-1362558.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['ray-ban','round','metal','vintage','men','gold'], ARRAY['frames','men','metal','round','vintage'], '{"frame_shape": "Round", "material": "Metal", "color": "Gold", "gender": "Men", "size": "Small", "weight": "20g", "warranty": "1 Year"}', 120, 800),
('RB-REC-002', 'Ray-Ban Rectangle Tortoise', 'Elegant rectangle frame in tortoise shell pattern. Sophisticated look for professionals.', '4028d001-d3ed-46a1-a744-96e3d6f5a0e4', '1d33ac1e-c860-4122-9c40-2ebe5c63203b', 10999, 7499, 18, ARRAY['https://images.pexels.com/photos/39716/pexels-photo-39716.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/1362558/pexels-photo-1362558.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['ray-ban','rectangle','tortoise','acetate','men','professional'], ARRAY['frames','men','acetate','rectangle','professional'], '{"frame_shape": "Rectangle", "material": "Acetate", "color": "Tortoise", "gender": "Men", "size": "Medium", "weight": "28g", "warranty": "1 Year"}', 150, 900),
('RB-CAT-002', 'Ray-Ban Cat Eye Rose Gold', 'Stylish cat-eye frame in rose gold metal. Feminine and trendy design.', '4028d001-d3ed-46a1-a744-96e3d6f5a0e4', '51239eab-0ea2-41a4-85e6-b4d664d845da', 11999, 8499, 18, ARRAY['https://images.pexels.com/photos/1366919/pexels-photo-1366919.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/147641/pexels-photo-147641.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['ray-ban','cat-eye','women','rose-gold','metal','fashion'], ARRAY['frames','women','metal','cat-eye','fashion'], '{"frame_shape": "Cat Eye", "material": "Metal", "color": "Rose Gold", "gender": "Women", "size": "Medium", "weight": "22g", "warranty": "1 Year"}', 100, 700);
INSERT INTO products (sku, name, description, brand_id, category_id, mrp, price, gst_rate, image_urls, is_active, is_featured, search_keywords, tags, specifications, popularity, view_count) VALUES
('RB-SUN-001', 'Ray-Ban Aviator Sunglasses Polarized', 'Classic aviator sunglasses with polarized lenses. UV400 protection.', '4028d001-d3ed-46a1-a744-96e3d6f5a0e4', 'c1562fe4-ee3e-40ca-a4af-be26402fbefa', 15999, 10999, 18, ARRAY['https://images.pexels.com/photos/39716/pexels-photo-39716.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/701841/pexels-photo-701841.jpeg?auto=compress&cs=tinysrgb&w=600'], true, true, ARRAY['ray-ban','sunglasses','aviator','polarized','uv400','men'], ARRAY['sunglasses','men','metal','aviator','polarized'], '{"frame_shape": "Aviator", "material": "Metal", "color": "Gold", "gender": "Men", "size": "Medium", "lens_type": "Polarized", "uv_protection": "UV400", "weight": "30g", "warranty": "2 Years"}', 250, 2000),
('RB-SUN-002', 'Ray-Ban Wayfarer Sunglasses Black', 'Original wayfarer sunglasses with crystal green lenses. Full UV protection.', '4028d001-d3ed-46a1-a744-96e3d6f5a0e4', 'c1562fe4-ee3e-40ca-a4af-be26402fbefa', 13999, 9499, 18, ARRAY['https://images.pexels.com/photos/701841/pexels-photo-701841.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/947885/pexels-photo-947885.jpeg?auto=compress&cs=tinysrgb&w=600'], true, true, ARRAY['ray-ban','sunglasses','wayfarer','black','acetate','unisex'], ARRAY['sunglasses','unisex','acetate','wayfarer','classic'], '{"frame_shape": "Wayfarer", "material": "Acetate", "color": "Black", "gender": "Unisex", "size": "Medium", "lens_type": "Standard", "uv_protection": "UV400", "weight": "35g", "warranty": "2 Years"}', 220, 1800),
('RB-SUN-003', 'Ray-Ban Clubmaster Sunglasses', 'Retro-inspired clubmaster sunglasses. Acetate top with metal bottom rim.', '4028d001-d3ed-46a1-a744-96e3d6f5a0e4', 'c1562fe4-ee3e-40ca-a4af-be26402fbefa', 14999, 9999, 18, ARRAY['https://images.pexels.com/photos/147641/pexels-photo-147641.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/39716/pexels-photo-39716.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['ray-ban','sunglasses','clubmaster','browline','retro','men'], ARRAY['sunglasses','men','clubmaster','retro','acetate'], '{"frame_shape": "Clubmaster", "material": "Acetate-Metal", "color": "Black-Gold", "gender": "Men", "size": "Medium", "lens_type": "Standard", "uv_protection": "UV400", "weight": "28g", "warranty": "2 Years"}', 180, 1400),
('RB-SUN-004', 'Ray-Ban Oversized Gradient Women', 'Oversized sunglasses with gradient lenses for women. Trendy and glamorous.', '4028d001-d3ed-46a1-a744-96e3d6f5a0e4', 'b265a223-a264-480d-97ac-cf785d6d4dab', 12999, 8499, 18, ARRAY['https://images.pexels.com/photos/1366919/pexels-photo-1366919.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/147641/pexels-photo-147641.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['ray-ban','sunglasses','oversized','gradient','women','fashion'], ARRAY['sunglasses','women','oversized','gradient','fashion'], '{"frame_shape": "Oversized", "material": "Acetate", "color": "Black", "gender": "Women", "size": "Large", "lens_type": "Gradient", "uv_protection": "UV400", "weight": "30g", "warranty": "2 Years"}', 130, 1000),
('RB-SUN-005', 'Ray-Ban Sports Wrap Sunglasses', 'Performance wrap-around sports sunglasses. Rubber grip temples. Anti-slip nose pads.', '4028d001-d3ed-46a1-a744-96e3d6f5a0e4', 'c1562fe4-ee3e-40ca-a4af-be26402fbefa', 11999, 7999, 18, ARRAY['https://images.pexels.com/photos/947885/pexels-photo-947885.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/39716/pexels-photo-39716.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['ray-ban','sunglasses','sports','wrap','men','active'], ARRAY['sunglasses','men','sports','wrap','active'], '{"frame_shape": "Wrap", "material": "TR90", "color": "Black", "gender": "Men", "size": "Medium", "lens_type": "Standard", "uv_protection": "UV400", "weight": "26g", "warranty": "2 Years"}', 90, 600);
