('OK-REC-001', 'Oakley Holbrook Rectangle', 'Premium rectangle frame with O-Matter material. Lightweight yet durable.', 'fcd8a540-5727-4c93-91a5-bfe38ea9459e', '1d33ac1e-c860-4122-9c40-2ebe5c63203b', 8999, 5999, 18, ARRAY['https://images.pexels.com/photos/1362558/pexels-photo-1362558.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/701841/pexels-photo-701841.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['oakley','rectangle','o-matter','men','sports','durable'], ARRAY['frames','men','sports','rectangle','durable'], '{"frame_shape": "Rectangle", "material": "O-Matter", "color": "Matte Black", "gender": "Men", "size": "Medium", "weight": "22g", "warranty": "2 Years"}', 140, 900),
('OK-GEO-001', 'Oakley Geometric Titanium', 'Geometric titanium frame with modern angular design. Premium build quality.', 'fcd8a540-5727-4c93-91a5-bfe38ea9459e', '1d33ac1e-c860-4122-9c40-2ebe5c63203b', 15999, 10999, 18, ARRAY['https://images.pexels.com/photos/147641/pexels-photo-147641.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/701841/pexels-photo-701841.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['oakley','geometric','titanium','men','premium','modern'], ARRAY['frames','men','titanium','geometric','premium'], '{"frame_shape": "Geometric", "material": "Titanium", "color": "Gunmetal", "gender": "Men", "size": "Medium", "weight": "18g", "warranty": "2 Years"}', 80, 500),
('OK-WAY-001', 'Oakley Frogskins Lifestyle', 'Lifestyle sunglasses with classic wayfarer shape. O-Matter frame. Prizm lens options.', 'fcd8a540-5727-4c93-91a5-bfe38ea9459e', 'c1562fe4-ee3e-40ca-a4af-be26402fbefa', 9999, 6999, 18, ARRAY['https://images.pexels.com/photos/1362558/pexels-photo-1362558.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/701841/pexels-photo-701841.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['oakley','sunglasses','lifestyle','frogskins','unisex','casual'], ARRAY['sunglasses','unisex','lifestyle','casual','wayfarer'], '{"frame_shape": "Wayfarer", "material": "O-Matter", "color": "Matte Black", "gender": "Unisex", "size": "Medium", "lens_type": "Prizm", "uv_protection": "UV400", "weight": "24g", "warranty": "2 Years"}', 110, 750),
