('OK-SUN-002', 'Oakley Flak 2.0 XL', 'XL fit sports sunglasses with polarized lenses. High Definition Optics.', 'fcd8a540-5727-4c93-91a5-bfe38ea9459e', 'c1562fe4-ee3e-40ca-a4af-be26402fbefa', 17999, 12999, 18, ARRAY['https://images.pexels.com/photos/39716/pexels-photo-39716.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/947885/pexels-photo-947885.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['oakley','sunglasses','sports','polarized','xl','men'], ARRAY['sunglasses','men','sports','polarized','xl'], '{"frame_shape": "Rectangle", "material": "O-Matter", "color": "Matte Black", "gender": "Men", "size": "Large", "lens_type": "Polarized", "uv_protection": "UV400", "weight": "26g", "warranty": "2 Years"}', 100, 700),
('OK-SUN-003', 'Oakley Jawbreaker Cycling', 'High-performance cycling sunglasses with Switchlock lens change. Prizm Road lens.', 'fcd8a540-5727-4c93-91a5-bfe38ea9459e', 'c1562fe4-ee3e-40ca-a4af-be26402fbefa', 19999, 14999, 18, ARRAY['https://images.pexels.com/photos/947885/pexels-photo-947885.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/39716/pexels-photo-39716.jpeg?auto=compress&cs=tinysrgb&w=600'], true, true, ARRAY['oakley','sunglasses','cycling','prizm','performance','men'], ARRAY['sunglasses','men','sports','cycling','prizm'], '{"frame_shape": "Wrap", "material": "O-Matter", "color": "Matte Black", "gender": "Men", "size": "Large", "lens_type": "Prizm Road", "uv_protection": "UV400", "weight": "32g", "warranty": "2 Years"}', 160, 1100);
